{
  "query": "mutation CreateClinicalOrder($orderData: ClinicalOrderInput!) { createOrder(orderData: $orderData) { id resourceType status intent category { coding { system code display } text } priority code { coding { system code display } text } subject { reference display } encounter { reference } occurrenceDatetime authoredOn requester { reference display } performer { reference display } reasonCode { coding { system code display } text } note { text authorString time } patientInstruction supportingInfo { reference display } specimen { reference display } bodySite { coding { system code display } text } } }",
  "variables": {
    "orderData": {
      "status": "DRAFT",
      "intent": "ORDER",
      "priority": "ROUTINE",
      "code": {
        "text": "Comprehensive Metabolic Panel",
        "coding": [
          {
            "system": "http://loinc.org",
            "code": "24323-8",
            "display": "Comprehensive metabolic 2000 panel - Serum or Plasma"
          }
        ]
      },
      "subject": {
        "reference": "Patient/{{patient_id}}"
      },
      "encounter": {
        "reference": "Encounter/{{encounter_id}}"
      },
      "requester": {
        "reference": "Practitioner/{{practitioner_id}}"
      },
      "category": [
        {
          "coding": [
            {
              "system": "http://terminology.hl7.org/CodeSystem/observation-category",
              "code": "laboratory",
              "display": "Laboratory"
            }
          ],
          "text": "Laboratory Order"
        }
      ],
      "reasonCode": [
        {
          "coding": [
            {
              "system": "http://snomed.info/sct",
              "code": "410620009",
              "display": "Well child visit"
            }
          ],
          "text": "Annual physical examination"
        }
      ],
      "note": [
        {
          "text": "Fasting required - patient instructed. Draw between 7-9 AM.",
          "authorString": "Dr. Smith",
          "time": "2024-01-15T10:30:00Z"
        }
      ],
      "patientInstruction": "Please fast for 12 hours before blood draw. No food or drink except water after 8 PM the night before.",
      "supportingInfo": [
        {
          "reference": "Observation/previous-lab-123"
        }
      ],
      "specimen": [
        {
          "reference": "Specimen/serum-sample-456"
        }
      ],
      "bodySite": [
        {
          "coding": [
            {
              "system": "http://snomed.info/sct",
              "code": "368209003",
              "display": "Right arm"
            }
          ],
          "text": "Right antecubital fossa"
        }
      ]
    }
  }
}

{
  "query": "mutation CreateMedicationOrder($orderData: MedicationOrderInput!) { createMedicationOrder(orderData: $orderData) { id resourceType status intent priority medicationCodeableConcept { coding { system code display } text } subject { reference display } encounter { reference } requester { reference display } dosageInstruction { text timing { repeat { frequency period periodUnit } } route { coding { system code display } } doseAndRate { doseQuantity { value unit system code } } } dispenseRequest { quantity { value unit } expectedSupplyDuration { value unit } numberOfRepeatsAllowed performer { reference display } } substitution { allowedBoolean reason { coding { system code display } } } reasonCode { coding { system code display } text } note { text authorString time } } }",
  "variables": {
    "orderData": {
      "status": "draft",
      "intent": "order",
      "priority": "routine",
      "medicationCodeableConcept": {
        "text": "Lisinopril 10mg Tablet",
        "coding": [
          {
            "system": "http://www.nlm.nih.gov/research/umls/rxnorm",
            "code": "314076",
            "display": "Lisinopril 10 MG Oral Tablet"
          }
        ]
      },
      "subject": {
        "reference": "Patient/{{patient_id}}"
      },
      "encounter": {
        "reference": "Encounter/{{encounter_id}}"
      },
      "requester": {
        "reference": "Practitioner/{{practitioner_id}}"
      },
      "dosageInstruction": [
        {
          "text": "Take 1 tablet by mouth daily in the morning with food",
          "timing": {
            "repeat": {
              "frequency": 1,
              "period": 1,
              "periodUnit": "d",
              "timeOfDay": [
                "08:00:00"
              ],
              "when": [
                "CM"
              ]
            }
          },
          "route": {
            "coding": [
              {
                "system": "http://snomed.info/sct",
                "code": "26643006",
                "display": "Oral route"
              }
            ]
          },
          "doseAndRate": [
            {
              "doseQuantity": {
                "value": 10,
                "unit": "mg",
                "system": "http://unitsofmeasure.org",
                "code": "mg"
              }
            }
          ],
          "maxDosePerPeriod": {
            "numerator": {
              "value": 10,
              "unit": "mg"
            },
            "denominator": {
              "value": 1,
              "unit": "d"
            }
          }
        }
      ],
      "dispenseRequest": {
        "quantity": {
          "value": 30,
          "unit": "tablet"
        },
        "expectedSupplyDuration": {
          "value": 30,
          "unit": "days"
        },
        "numberOfRepeatsAllowed": 5,
        "performer": {
          "reference": "Organization/pharmacy-123"
        }
      },
      "substitution": {
        "allowedBoolean": true,
        "reason": {
          "coding": [
            {
              "system": "http://terminology.hl7.org/CodeSystem/v3-ActReason",
              "code": "FP",
              "display": "formulary policy"
            }
          ]
        }
      },
      "reasonCode": [
        {
          "coding": [
            {
              "system": "http://snomed.info/sct",
              "code": "38341003",
              "display": "Hypertensive disorder"
            }
          ],
          "text": "Essential hypertension"
        }
      ],
      "note": [
        {
          "text": "Monitor blood pressure weekly. Target BP <140/90. Check renal function in 2 weeks.",
          "authorString": "Dr. Smith",
          "time": "2024-01-15T10:30:00Z"
        }
      ]
    }
  }
}

{
  "query": "mutation CreateOrderWithCDS($orderData: ClinicalOrderInput!, $cdsOptions: CDSOptionsInput!) { createOrderWithCDS(orderData: $orderData, cdsOptions: $cdsOptions) { order { id resourceType status intent code { text } subject { reference } } cdsAlerts { alertType severity message recommendation source { system code display } } drugInteractions { severity interactingMedications { name rxnormCode } mechanism clinicalEffect recommendation } allergyAlerts { allergen { name code } severity reaction { type description } recommendation } } }",
  "variables": {
    "orderData": {
      "status": "draft",
      "intent": "order",
      "code": {
        "text": "Warfarin 5mg daily",
        "coding": [
          {
            "system": "http://www.nlm.nih.gov/research/umls/rxnorm",
            "code": "855332",
            "display": "Warfarin Sodium 5 MG Oral Tablet"
          }
        ]
      },
      "subject": {
        "reference": "Patient/{{patient_id}}"
      },
      "encounter": {
        "reference": "Encounter/{{encounter_id}}"
      },
      "requester": {
        "reference": "Practitioner/{{practitioner_id}}"
      },
      "reasonCode": [
        {
          "text": "Atrial fibrillation anticoagulation"
        }
      ]
    },
    "cdsOptions": {
      "checkDrugInteractions": true,
      "checkAllergies": true,
      "checkDuplicateTherapy": true,
      "checkContraindications": true,
      "checkDosing": true,
      "includeRecommendations": true
    }
  }
}

{
  "query": "query CheckDrugInteractions($patientId: ID!, $medications: [MedicationInput!]!) { checkDrugInteractions(patientId: $patientId, medications: $medications) { severity interactingMedications { name rxnormCode currentDose } mechanism clinicalEffect recommendation evidenceLevel source { system code display } managementStrategy { action description monitoring } } }",
  "variables": {
    "patientId": "{{patient_id}}",
    "medications": [
      {
        "name": "Warfarin",
        "rxnormCode": "11289",
        "dose": "5mg daily"
      },
      {
        "name": "Aspirin",
        "rxnormCode": "1191",
        "dose": "81mg daily"
      },
      {
        "name": "Simvastatin",
        "rxnormCode": "36567",
        "dose": "20mg daily"
      }
    ]
  }
}

{
  "query": "mutation CreateOrderSet($orderSetData: OrderSetInput!) { createOrderSet(orderSetData: $orderSetData) { id name description category { text } status orders { type priority code { text } dosageInstruction { text } } applicableConditions { coding { system code display } text } customizations { field options defaultValue } metadata { version author { reference display } dateCreated lastModified } } }",
  "variables": {
    "orderSetData": {
      "name": "Hypertension Management Protocol",
      "description": "Comprehensive order set for newly diagnosed hypertension management including medications, monitoring, and lifestyle interventions",
      "category": {
        "text": "Cardiovascular",
        "coding": [
          {
            "system": "http://snomed.info/sct",
            "code": "38341003",
            "display": "Hypertensive disorder"
          }
        ]
      },
      "status": "active",
      "orders": [
        {
          "type": "medication",
          "priority": "routine",
          "code": {
            "text": "Lisinopril 10mg daily",
            "coding": [
              {
                "system": "http://www.nlm.nih.gov/research/umls/rxnorm",
                "code": "314076",
                "display": "Lisinopril 10 MG Oral Tablet"
              }
            ]
          },
          "dosageInstruction": {
            "text": "Take 1 tablet by mouth daily in the morning"
          }
        },
        {
          "type": "clinical",
          "priority": "routine",
          "code": {
            "text": "Blood pressure monitoring every 4 hours",
            "coding": [
              {
                "system": "http://snomed.info/sct",
                "code": "182744004",
                "display": "Blood pressure monitoring"
              }
            ]
          }
        },
        {
          "type": "clinical",
          "priority": "routine",
          "code": {
            "text": "Low sodium diet consultation",
            "coding": [
              {
                "system": "http://snomed.info/sct",
                "code": "226234005",
                "display": "Low sodium diet"
              }
            ]
          }
        },
        {
          "type": "clinical",
          "priority": "routine",
          "code": {
            "text": "Basic metabolic panel in 2 weeks",
            "coding": [
              {
                "system": "http://loinc.org",
                "code": "51990-0",
                "display": "Basic metabolic 2000 panel"
              }
            ]
          }
        }
      ],
      "applicableConditions": [
        {
          "coding": [
            {
              "system": "http://snomed.info/sct",
              "code": "59621000",
              "display": "Essential hypertension"
            }
          ],
          "text": "Essential hypertension"
        }
      ],
      "customizations": [
        {
          "field": "lisinopril_dose",
          "options": [
            "5mg",
            "10mg",
            "20mg"
          ],
          "defaultValue": "10mg"
        },
        {
          "field": "monitoring_frequency",
          "options": [
            "q2h",
            "q4h",
            "q6h",
            "q8h"
          ],
          "defaultValue": "q4h"
        }
      ],
      "metadata": {
        "version": "1.0",
        "author": {
          "reference": "Practitioner/{{practitioner_id}}"
        }
      }
    }
  }
}

{
  "query": "mutation SignOrder($orderId: ID!, $signatureData: SignatureInput!) { signOrder(id: $orderId, signatureData: $signatureData) { id status intent authoredOn requester { reference display } signature { type signedOn signer { reference display } digitalSignature { algorithm hash timestamp } } statusHistory { status timestamp reason user { reference display } } } }",
  "variables": {
    "orderId": "{{order_id}}",
    "signatureData": {
      "type": "electronic",
      "signer": {
        "reference": "Practitioner/{{practitioner_id}}"
      },
      "signedOn": "2024-01-15T10:30:00Z",
      "digitalSignature": {
        "algorithm": "SHA-256",
        "hash": "a1b2c3d4e5f6...",
        "timestamp": "2024-01-15T10:30:00Z"
      },
      "reason": "Order reviewed and approved for patient care"
    }
  }
}

{
  "query": "mutation HoldOrder($orderId: ID!, $holdData: OrderActionInput!) { holdOrder(id: $orderId, holdData: $holdData) { id status statusReason { coding { system code display } text } statusHistory { status timestamp reason user { reference display } } note { text authorString time } } }",
  "variables": {
    "orderId": "{{order_id}}",
    "holdData": {
      "reason": "Patient allergic reaction reported - reviewing alternative medications",
      "reasonCode": {
        "coding": [
          {
            "system": "http://terminology.hl7.org/CodeSystem/v3-ActReason",
            "code": "ALTCHOICE",
            "display": "Alternative choice"
          }
        ],
        "text": "Allergy concern"
      },
      "user": {
        "reference": "Practitioner/{{practitioner_id}}"
      },
      "timestamp": "2024-01-15T11:00:00Z",
      "note": "Patient reported rash after first dose. Holding order pending allergy evaluation."
    }
  }
}

{
  "query": "query PatientWithOrders($id: ID!) { patient(id: $id) { id resourceType identifier { system value } name { given family } gender birthDate active orders { id resourceType status intent priority code { text } authoredOn requester { reference display } reasonCode { text } } observations { id status code { text } effectiveDateTime valueQuantity { value unit } } medications { id status medicationCodeableConcept { text } dosageInstruction { text } } } }",
  "variables": {
    "id": "{{patient_id}}"
  }
}

{
  "query": "query EncounterWithOrders($id: ID!) { encounter(id: $id) { id status class { system code display } subject { reference display } period { start end } orders { id status intent code { text } authoredOn requester { reference display } } diagnoses { condition { reference display } } procedures { procedure { reference display } } } }",
  "variables": {
    "id": "{{encounter_id}}"
  }
}

{
  "query": "query GetOrderHistory($orderId: ID!) { orderHistory(orderId: $orderId) { order { id resourceType status intent code { text } } auditTrail { action timestamp user { reference display } details { field oldValue newValue } reason ipAddress userAgent } statusHistory { status timestamp reason user { reference display } } modifications { field oldValue newValue timestamp user { reference display } reason } signatures { type signedOn signer { reference display } digitalSignature { algorithm hash timestamp } } } }",
  "variables": {
    "orderId": "{{order_id}}"
  }
}

{
  "query": "query IntrospectionQuery { __schema { queryType { name } mutationType { name } subscriptionType { name } types { ...FullType } directives { name description locations args { ...InputValue } } } } fragment FullType on __Type { kind name description fields(includeDeprecated: true) { name description args { ...InputValue } type { ...TypeRef } isDeprecated deprecationReason } inputFields { ...InputValue } interfaces { ...TypeRef } enumValues(includeDeprecated: true) { name description isDeprecated deprecationReason } possibleTypes { ...TypeRef } } fragment InputValue on __InputValue { name description type { ...TypeRef } defaultValue } fragment TypeRef on __Type { kind name ofType { kind name ofType { kind name ofType { kind name ofType { kind name ofType { kind name ofType { kind name ofType { kind name } } } } } } } }"
}

{
  "query": "query GetOrderTypes { __schema { types { name kind description fields { name type { name kind } } } } }"
}

{
  "query": "query GetAvailableOperations { __schema { queryType { fields { name description args { name type { name } } type { name } } } mutationType { fields { name description args { name type { name } } type { name } } } } }"
}
